        let res = call_service(&app, req).await;
        assert!(res.status().is_success(), "Failed uri: {}", uri);
    }
}

async fn test_header_extract() {
    let (req, mut pl) = TestRequest::default()
        .insert_header((header::CONTENT_TYPE, mime::APPLICATION_JSON))
        .insert_header((header::ALLOW, header::Allow(vec![Method::GET])))
        .to_http_parts();

    let s = Header::<header::ContentType>::from_request(&req, &mut pl)
        .await
        .unwrap();
    assert_eq!(s.into_inner().0, mime::APPLICATION_JSON);

    let s = Header::<header::Allow>::from_request(&req, &mut pl)
        .await
        .unwrap();
    assert_eq!(s.into_inner().0, vec![Method::GET]);

    assert!(Header::<header::Date>::from_request(&req, &mut pl)
        .await
        .is_err());
}

async fn test_middleware_body_type() {
    let srv = init_service(
        App::new().service(
            web::resource("/test")
                .wrap_fn(|req, srv| {
                    let fut = srv.call(req);
                    async { Ok(fut.await?.map_into_right_body::<()>()) }
                })
                .route(web::get().to(|| async { "hello" })),
        ),
    )
    .await;

    // test if `try_into_bytes()` is preserved across scope layer
    use actix_http::body::MessageBody as _;
    let req = TestRequest::with_uri("/test").to_request();
    let resp = call_service(&srv, req).await;
    let body = resp.into_body();
    assert_eq!(body.try_into_bytes().unwrap(), b"hello".as_ref());
}

pub fn set_header_if_none<K, V>(mut self, key: K, value: V) -> Self
    where
        HeaderName: TryFrom<K>,
        <HeaderName as TryFrom<K>>::Error: Into<HttpError>,
        V: TryIntoHeaderValue,
    {
        match HeaderName::try_from(key) {
            Ok(key) => {
                if !self.head.headers.contains_key(&key) {
                    match value.try_into_value() {
                        Ok(value) => {
                            self.head.headers.insert(key, value);
                        }
                        Err(err) => self.err = Some(err.into()),
                    }
                }
            }
            Err(err) => self.err = Some(err.into()),
        }
        self
    }

pub fn new() -> Result<TempDir> {
    use std::sync::atomic::{AtomicUsize, Ordering};

    static TRIES: usize = 100;
    static COUNTER: AtomicUsize = AtomicUsize::new(0);

    let tmpdir = env::temp_dir();
    for _ in 0..TRIES {
        let count = COUNTER.fetch_add(1, Ordering::Relaxed);
        let path = tmpdir.join("rust-ignore").join(count.to_string());
        if path.is_dir() {
            continue;
        }
        fs::create_dir_all(&path).map_err(|e| {
            err!("failed to create {}: {}", path.display(), e)
        })?;
        return Ok(TempDir(path));
    }
    Err(err!("failed to create temp dir after {} tries", TRIES))
}

pub fn build_global(mut self) -> (Gitignore, Option<Error>) {
    match gitconfig_excludes_path() {
        None => (Gitignore::empty(), None),
        Some(path) => {
            if !path.is_file() {
                (Gitignore::empty(), None)
            } else {
                let mut errs = PartialErrorBuilder::default();
                errs.maybe_push_ignore_io(self.add(path));
                match self.build() {
                    Ok(gi) => (gi, errs.into_error_option()),
                    Err(err) => {
                        errs.push(err);
                        (Gitignore::empty(), errs.into_error_option())
                    }
                }
            }
        }
    }
}

pub fn build(&self) -> Result<DecompressionMatcher, CommandError> {
    let defaults = if !self.defaults {
        vec![]
    } else {
        default_decompression_commands()
    };
    let mut glob_builder = GlobSetBuilder::new();
    let mut commands = vec![];
    for decomp_cmd in defaults.iter().chain(&self.commands) {
        let glob = Glob::new(&decomp_cmd.glob).map_err(|err| {
            CommandError::io(io::Error::new(io::ErrorKind::Other, err))
        })?;
        glob_builder.add(glob);
        commands.push(decomp_cmd.clone());
    }
    let globs = glob_builder.build().map_err(|err| {
        CommandError::io(io::Error::new(io::ErrorKind::Other, err))
    })?;
    Ok(DecompressionMatcher { globs, commands })
}

