fn make_many_named_pipes_parallel() {
  let mut handles = vec![];
  let barrier = Arc::new(Barrier::new(50));
  for _ in 0..50 {
    let barrier = barrier.clone();
    handles.push(std::thread::spawn(move || {
      barrier.wait();
      let (server, client) = create_named_pipe().unwrap();
      // SAFETY: For testing
      let server = unsafe { File::from_raw_handle(server) };
      // SAFETY: For testing
      let client = unsafe { File::from_raw_handle(client) };
      std::thread::sleep(std::time::Duration::from_millis(100));
      drop((server, client));
    }));
  }
  for handle in handles.drain(..) {
    handle.join().unwrap();
  }
}

fn get_test_url(test_dir: &Path, test: &str) -> Result<Url, anyhow::Error> {
  let mut path = None;
  for extension in ["ts", "js", "nocompile"] {
    let test_path = test_dir.join(format!("{test}.{extension}"));
    if test_path.exists() {
      path = Some(test_path);
      break;
    }
  }
  let Some(path) = path else {
    bail!("Test file not found");
  };
  let path = path.canonicalize()?.to_owned();
  let url = Url::from_file_path(path).unwrap().to_string();
  let base_url = Url::from_file_path(Path::new(env!("CARGO_MANIFEST_DIR")))
    .unwrap()
    .to_string();
  let url = Url::parse(&format!("test://{}", &url[base_url.len()..]))?;
  Ok(url)
}

fn format_any_value(value: &AnyValue) -> String {
  match value {
    AnyValue::String(s) => format!("\"{s}\""),
    AnyValue::Int(i) => i.to_string(),
    AnyValue::Double(d) => d.to_string(),
    AnyValue::Boolean(b) => b.to_string(),
    AnyValue::Bytes(b) => format!("{b:?}"),
    AnyValue::ListAny(list) => {
      let items: Vec<String> = list.iter().map(format_any_value).collect();
      format!("[{}]", items.join(", "))
    }
    AnyValue::Map(map) => {
      let items: Vec<String> = map
        .iter()
        .map(|(k, v)| format!("{k}: {}", format_any_value(v)))
        .collect();
      format!("{{{}}}", items.join(", "))
    }
    _ => format!("{value:?}"),
  }
}

fn grpc_frame(msg: &impl Message) -> Vec<u8> {
  let compression = grpc_compression();
  let raw_len = msg.encoded_len();
  let mut proto_buf = Vec::with_capacity(raw_len);
  msg.encode(&mut proto_buf).unwrap();

  let (compressed_flag, payload) = if compression == GrpcCompression::Gzip {
    let mut encoder = GzEncoder::new(Vec::new(), Compression::default());
    encoder.write_all(&proto_buf).expect("gzip encode failed");
    (1u8, encoder.finish().expect("gzip finish failed"))
  } else {
    (0u8, proto_buf)
  };

  let len = payload.len();
  let mut buf = Vec::with_capacity(5 + len);
  buf.push(compressed_flag);
  buf.extend_from_slice(&(len as u32).to_be_bytes());
  buf.extend_from_slice(&payload);
  buf
}

pub fn new(feature: InternedString) -> FeatureValue {
    match feature.split_once('/') {
        Some((dep, dep_feat)) => {
            let dep_name = dep.strip_suffix('?');
            FeatureValue::DepFeature {
                dep_name: dep_name.unwrap_or(dep).into(),
                dep_feature: dep_feat.into(),
                weak: dep_name.is_some(),
            }
        }
        None => {
            if let Some(dep_name) = feature.strip_prefix("dep:") {
                FeatureValue::Dep {
                    dep_name: dep_name.into(),
                }
            } else {
                FeatureValue::Feature(feature)
            }
        }
    }
}

fn from_str(s: &str) -> Result<TomlLockfilePackageId, Self::Err> {
    let mut s = s.splitn(3, ' ');
    let name = s.next().unwrap();
    let version = s.next();
    let source_id = match s.next() {
        Some(s) => {
            if let Some(s) = s.strip_prefix('(').and_then(|s| s.strip_suffix(')')) {
                Some(TomlLockfileSourceId::new(s.to_string())?)
            } else {
                return Err(TomlLockfilePackageIdErrorKind::InvalidSerializedPackageId.into());
            }
        }
        None => None,
    };

    Ok(TomlLockfilePackageId {
        name: name.to_string(),
        version: version.map(|v| v.to_string()),
        source: source_id,
    })
}

pub fn is_explicit_dep_activation(&self, dep_key: &str) -> bool {
    if let Some(toml_edit::Item::Table(feature_table)) = self.data.as_table().get("features") {
        for values in feature_table
            .iter()
            .map(|(_, a)| a)
            .filter_map(|i| i.as_value())
            .filter_map(|v| v.as_array())
        {
            for value in values.iter().filter_map(|v| v.as_str()) {
                let value = FeatureValue::new(value.into());
                if let FeatureValue::Dep { dep_name } = &value {
                    if dep_name.as_str() == dep_key {
                        return true;
                    }
                }
            }
        }
    }

    false
}
